<?php
 namespace WPAICG\Chat\Storage; use WPAICG\Chat\Storage\SiteWideBotManager; use WP_Error; require_once __DIR__ . '/saver/methods.php'; if (!defined('ABSPATH')) { exit; } class AIPKit_Bot_Settings_Saver { private $site_wide_manager; public function __construct(SiteWideBotManager $site_wide_manager) { $this->site_wide_manager = $site_wide_manager; } public function save(int $botId, array $raw_settings): bool|WP_Error { if (!$this->site_wide_manager) { return new WP_Error('dependency_missing_saver', __('Site-wide manager component is missing.', 'gpt3-ai-content-generator')); } return SaverMethods\save_bot_settings_logic($botId, $raw_settings, $this->site_wide_manager); } } 